var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"끄흠… 낭패로구나…","JPN":"ぐう……まさかっ、こんなことに……","ENG":"Agh… This is a disaster…","TWN":"咳… 真糟糕…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"우리 삼군문이… 뭔지도 모를 저 괴물에게 전부 당하다니… 쿨럭…","JPN":"我々三軍門が……得体の知れないあの化け物にやられるとは……ゴホッ……","ENG":"To think… the entire Trivanguard was wiped out by some monster we don't even recognize… *Cough…*","TWN":"我們三軍門… 竟然被那個不知道是什麼的怪物給全滅了… 咳…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"침식에 오염된 상처는 여럿 보아왔으나… 이토록 하얀 상처는 처음 보는구려.","JPN":"侵食に汚染された傷は今まで多く見て来たが……こうも白い傷は初めてである。","ENG":"I've seen my fair share of Corruption wounds, but… I've never seen one this pale before.","TWN":"我見過許多被侵蝕污染的傷口… 但像這樣潔白的傷口，我還是第一次見。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…다른 전대와 연락이 닿지 않아.","JPN":"……他の戦隊と連絡ができないわ。","ENG":"…We still can't reach any of the other divisions.","TWN":"…無法聯繫到其他戰隊。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"아무래도 관리국의 상황이 예상보다 나쁜 모양이군.","JPN":"どうやら管理局の状況は予想よりも深刻なようだ。","ENG":"Then it's safe to say the Administration is in worse shape than we thought.","TWN":"看來管理局的狀況比預想的還要糟糕。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하담, 양상 어른을 부탁해. 내가 의사를 모셔올게.","JPN":"カタン、リョウジさんをお願い。私が医者を呼んでくるわ。","ENG":"Ha Dam, please take care of Elder Yangsang. I'll go find a doctor.","TWN":"夏垣，梁尚叔就拜託你了。我去請醫生。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"아니. 가지 말아라. 너희에게 전할 말이 있다.","JPN":"いや、行くな。お前たちに伝えねばならないことがある。","ENG":"No. Don't go. I've something I need to say to you both.","TWN":"不。別去。我有話要告訴你們。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그런 건 치료를 한 뒤에도 늦지 않습니다.","JPN":"そんなの、治療が終わってからでも遅くありません。","ENG":"That can wait until after we get you treated.","TWN":"這種事治療之後再說也不遲。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"그냥 곁에 있거라. 부질없는 짓으로 내 남은 시간을 허비하고 싶진 않구나.","JPN":"そうせずともよい。余計なことで、私に残された時間を無駄にしたくはない。","ENG":"Just stay by my side. I don’t wish to waste what little time I have left on meaningless things.","TWN":"就待在我身邊吧。我不想浪費我剩下的時間去做無用的事。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"그리 상심한 표정 짓지 말아라. 다시 일어서야 할 것 아니냐?","JPN":"そう落胆するな。再び立ち上がらねばならないんだぞ。","ENG":"Don't look so broken up. You've still got to stand back up, don't you?","TWN":"不要露出這麼悲傷的表情。不是還要重新振作起來嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이런 상황에, 남겨진 저희가 뭘 할 수 있나요?","JPN":"こんな状況で、残された私たちに何ができるというのですか？","ENG":"After all this, what are we even supposed to do?","TWN":"在這種情況下，我們這些剩下的人還能做什麼？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"명달 영감님께선… 나전 천갑이 무너지면 범을 막을 인재는 너희 둘 뿐이라 하셨다.","JPN":"アカタツ殿は……螺鈿天甲が崩れたら、虎を止められる者はお前たち2人だけだと仰った。","ENG":"Old Myeongdal once said… if the Heavenly Inlaid Armor ever fails, only the two of you would be left who could stop the Tiger.","TWN":"明達老頭說過… 如果螺鈿天甲瓦解，能阻止老虎的人就只剩下你們兩個了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"그러니 우리가 다 죽는 한이 있어도… 너희가 살았다면 의미는 있는 게지.","JPN":"だから、他の皆が散ろうとも……お前たち2人が生きているなら、意味がある。","ENG":"So even if we all fall… if you two survive, that's enough to make it matter.","TWN":"所以就算我們都死了… 只要你們活著，就有意義。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"하담아. 이 늙은이 잔소리 한 번 들어주겠니?","JPN":"カタン。この老いぼれの小言を聞いてくれるか。","ENG":"Ha Dam. Would you indulge this old man one last rant?","TWN":"夏垣。你能聽我這個阿姨再嘮叨一次嗎？"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…경청하오리다. 양상 어른.","JPN":"……ああ、リョウジ殿。","ENG":"…I'm listening, sir.","TWN":"…我會洗耳恭聽的，梁尚叔。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"네가 했던 말처럼… 가족을 꾸리고 지킨다는 일은 결코 쉽지 않을 거다.","JPN":"お前が言った通り……家庭を作り守り抜くことは決して容易いことではない。","ENG":"Just like you said… building a family and keeping it together won't be easy.","TWN":"就像你說的那樣… 組織家庭、守護家庭絕非易事。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"허나 도공이 힘들게 빚은 도자기는 그만큼 아름다울 것이요. 또한 언제 깨질지 모르는 그런 연약한 것이기에…","JPN":"しかし、職人が丹精込めて作った陶磁器はその分美しいものであり、また、いつ割れるか分からない脆いものだからこそ……","ENG":"But a potter's jar, shaped with care and effort, holds beauty. Fragile as it may be, never knowing when it'll crack…","TWN":"但是，陶工辛勤製作的瓷器，因此而美麗。又因為那是隨時可能破碎的脆弱之物…"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"…그만큼 간절한 마음으로 빚어내는 것이라 생각한다.","JPN":"……それだけ切実な想いを込めて作るのだろう。","ENG":"…I believe that's why it's made with such longing in the first place.","TWN":"…所以我認為，他們會懷著那樣迫切的心情去製作。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"깨어질까 두려워 지레 겁먹지 말거라.","JPN":"壊れることを恐れて怯えるな。","ENG":"Don't fear breakage before it happens.","TWN":"不要因為害怕破碎而退縮。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"내일의 상실을 염려하여 오늘의 기꺼움을 피하지 말아라.","JPN":"来るかもわからない喪失を憂いて、今日の喜びから逃げるな。","ENG":"Don't avoid today's joy because of tomorrow's grief.","TWN":"不要因為擔心明日的失去，而迴避今日的喜悅。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"이것이…","JPN":"これが……","ENG":"This is…","TWN":"這就是…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"너희에게 남기는 내 마지막 잔소리다…","JPN":"私からの、最後の小言だ……","ENG":"The last piece of advice I'll ever give you…","TWN":"我留給你們最後的嘮叨…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…명심하리다.","JPN":"……肝に命じておこう。","ENG":"…I'll take it to heart.","TWN":"…我會銘記在心。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"양상은 양지 바른 곳에 묻었느냐?","JPN":"リョウジはいい場所に埋めてやったか。","ENG":"Did you lay Yangsang to rest in a sunny spot?","TWN":"梁尚，你把他葬在向陽的地方了嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};